HOST = "0.0.0.0"
PORT = 7777
TICK_RATE = 20.0
WORLD_SIZE = 1000.0
PLAYER_SPEED = 6.0
SEND_FULL_STATE_EVERY_TICKS = 1


def clamp(v, lo, hi):
    return max(lo, min(hi, v))


def distance2(a, b):
    dx = a[0] - b[0]
    dy = a[1] - b[1]
    dz = a[2] - b[2]
    return dx * dx + dy * dy + dz * dz


@dataclass
class Player:
    id: str
    name: str
    x: float = 0.0
    y: float = 0.0
    z: float = 0.0
    vx: float = 0.0
    vy: float = 0.0
